def get_composer_birth_year(name):
    composers = {
        "Arthur Honegger": 1892,
        "Johann Sebastian Bach": 1685,
        "Richard Wagner": 1813
    }
    return composers.get(name, None)

# Example usage:
print(get_composer_birth_year("Arthur Honegger"))  # Output: 1892
